interface AddItemAction {
  type: 'addItem';
  /**
   * \u65B0\u589E\u7684\u8282\u70B9
   */
  item: T;
  /**
   * \u65B0\u589E\u8282\u70B9\u7684\u4F4D\u7F6E\uFF0C\u4E0D\u4F20\u5219\u9ED8\u8BA4\u5728\u6700\u540E
   */
  index?: number;
}

// \u79FB\u52A8\u8282\u70B9
interface MoveItemAction {
  type: 'moveItem';
  /**
   * \u5F53\u524D\u8282\u70B9\u7D22\u5F15
   */
  activeIndex: number;
  /**
   * \u76EE\u6807\u8282\u70B9\u7D22\u5F15
   */
  overIndex: number;
}

// \u79FB\u9664\u8282\u70B9
interface RemoveItemAction {
  type: 'removeItem';
  /**
   * \u8981\u79FB\u9664\u7684\u8282\u70B9\u7684\u4F4D\u7F6E
   */
  index: number;
}

// \u4FEE\u6539\u8282\u70B9 content \u5185\u5BB9
interface UpdateItemAction {
  type: 'updateItem';
  /**
   * \u8981\u4FEE\u6539\u7684\u8282\u70B9\u7684\u4F4D\u7F6E
   */
  index: number;
  /**
   * \u4FEE\u6539\u540E\u7684\u8282\u70B9\u5185\u5BB9
   */
  item: Partial<T>;
}
